defmodule MyAppWeb.PostLive.Show do
  use MyAppWeb, :live_view
  alias MyApp.Blog

  def mount(%{"id" => id}, _session, socket) do
    post = Blog.get_post!(id)
    {:ok, assign(socket, post: post)}
  end

  def render(assigns) do
    ~L"""
    <div>
      <h1><%= @post.title %></h1>
      <div><%= safe_html(@post.content) %></div>
    </div>
    """
  end

  defp safe_html(content) do
    content
    |> MyApp.Sanitizer.sanitize() # Assuming you have a sanitizer module
    |> Phoenix.HTML.raw()
  end
end

